using System.Security.Claims;

namespace sv_c241bd20eaef4c7b83a0b3168b396a4e.Client;

public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }

    public ClaimsPrincipal ToClaimsPrincipal()
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, Email),
            new(ClaimTypes.Email, Email),
        };

        foreach (var role in Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        return new ClaimsPrincipal(identity);
    }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_c241bd20eaef4c7b83a0b3168b396a4e.Client;

/// <summary>
/// Reads the persisted user info that the server serialized into PersistentComponentState
/// so auth state survives the server → WebAssembly handoff.
/// </summary>
public sealed class ClientAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly AuthenticationState _anonymous =
        new(new ClaimsPrincipal(new ClaimsIdentity()));

    private readonly Task<AuthenticationState> _authState;

    public ClientAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>("UserInfo", out var userInfo) && userInfo is not null)
        {
            _authState = Task.FromResult(new AuthenticationState(userInfo.ToClaimsPrincipal()));
        }
        else
        {
            _authState = Task.FromResult(_anonymous);
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_c241bd20eaef4c7b83a0b3168b396a4e.Client;

namespace sv_c241bd20eaef4c7b83a0b3168b396a4e;

/// <summary>
/// Server-side AuthenticationStateProvider that returns a hardcoded user
/// and persists the user info into PersistentComponentState so the
/// WebAssembly runtime can pick it up after the interactive handoff.
/// </summary>
public sealed class ServerAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private static readonly UserInfo _user = new()
    {
        Email = "bob@example.com",
        Roles = ["User", "Editor"],
    };

    private readonly Task<AuthenticationState> _authState;
    private readonly PersistingComponentStateSubscription _subscription;

    public ServerAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _authState = Task.FromResult(new AuthenticationState(_user.ToClaimsPrincipal()));

        _subscription = persistentState.RegisterOnPersisting(() =>
        {
            persistentState.PersistAsJson("UserInfo", _user);
            return Task.CompletedTask;
        }, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;

    public void Dispose() => _subscription.Dispose();
}

@page "/profile"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Components.Authorization
@using System.Security.Claims
@inject AuthenticationStateProvider AuthStateProvider

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

@if (_userName is not null)
{
    <p><strong>Name:</strong> @_userName</p>
    <h3>Roles</h3>
    <ul>
        @foreach (var role in _roles)
        {
            <li>@role</li>
        }
    </ul>
}
else
{
    <p>Not authenticated.</p>
}

@code {
    private string? _userName;
    private string[] _roles = [];

    protected override async Task OnInitializedAsync()
    {
        var state = await AuthStateProvider.GetAuthenticationStateAsync();
        var user = state.User;

        if (user.Identity?.IsAuthenticated == true)
        {
            _userName = user.Identity.Name;
            _roles = user.Claims
                .Where(c => c.Type == ClaimTypes.Role)
                .Select(c => c.Value)
                .ToArray();
        }
    }
}

