using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_c241bd20eaef4c7b83a0b3168b396a4e.Client;

/// <summary>
/// Reads the persisted user info that the server serialized into PersistentComponentState
/// so auth state survives the server → WebAssembly handoff.
/// </summary>
public sealed class ClientAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly AuthenticationState _anonymous =
        new(new ClaimsPrincipal(new ClaimsIdentity()));

    private readonly Task<AuthenticationState> _authState;

    public ClientAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<UserInfo>("UserInfo", out var userInfo) && userInfo is not null)
        {
            _authState = Task.FromResult(new AuthenticationState(userInfo.ToClaimsPrincipal()));
        }
        else
        {
            _authState = Task.FromResult(_anonymous);
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;
}

